int LunariLanguage::debug_get_stack_level_count() const {
	return debug_stack.size();
}

int LunariLanguage::debug_get_stack_level_line(int p_level) const {
	ERR_FAIL_INDEX_V(p_level, debug_stack.size(), -1);
	return debug_stack[p_level].line;
}

String LunariLanguage::debug_get_stack_level_function(int p_level) const {
	ERR_FAIL_INDEX_V(p_level, debug_stack.size(), String());
	return debug_stack[p_level].function;
}

String LunariLanguage::debug_get_stack_level_source(int p_level) const {
	ERR_FAIL_INDEX_V(p_level, debug_stack.size(), String());
	return debug_stack[p_level].source;
}

void LunariLanguage::debug_get_stack_level_locals(int p_level, List<String> *p_locals, List<Variant> *p_values, int p_max_subitems, int p_max_depth) {
	ERR_FAIL_NULL(p_locals);
	ERR_FAIL_NULL(p_values);
	ERR_FAIL_INDEX(p_level, debug_stack.size());
	for (const KeyValue<StringName, Variant> &local : debug_stack[p_level].locals) {
		p_locals->push_back(local.key);
		p_values->push_back(local.value);
	}
}

void LunariLanguage::debug_get_stack_level_members(int p_level, List<String> *p_members, List<Variant> *p_values, int p_max_subitems, int p_max_depth) {
	ERR_FAIL_NULL(p_members);
	ERR_FAIL_NULL(p_values);
	ERR_FAIL_INDEX(p_level, debug_stack.size());
	for (const KeyValue<StringName, Variant> &member : debug_stack[p_level].members) {
		p_members->push_back(member.key);
		p_values->push_back(member.value);
	}
}

ScriptInstance *LunariLanguage::debug_get_stack_level_instance(int p_level) {
	ERR_FAIL_INDEX_V(p_level, debug_stack.size(), nullptr);
	return debug_stack[p_level].instance;
}

void LunariLanguage::debug_get_globals(List<String> *p_globals, List<Variant> *p_values, int p_max_subitems, int p_max_depth) {
	ERR_FAIL_NULL(p_globals);
	ERR_FAIL_NULL(p_values);
	for (const KeyValue<StringName, Variant> &global : global_constants) {
		p_globals->push_back(global.key);
		p_values->push_back(global.value);
	}
	List<Pair<String, Variant>> public_constants;
	get_public_constants(&public_constants);
	for (const Pair<String, Variant> &constant : public_constants) {
		p_globals->push_back(constant.first);
		p_values->push_back(constant.second);
	}
}

String LunariLanguage::debug_parse_stack_level_expression(int p_level, const String &p_expression, int p_max_subitems, int p_max_depth) {
	ERR_FAIL_INDEX_V(p_level, debug_stack.size(), String());
	const DebugFrame &frame = debug_stack[p_level];
	String expression = p_expression.strip_edges();
	if (expression.begins_with("self.")) {
		expression = expression.substr(5);
	}
	StringName expression_name = expression;
	if (frame.locals.has(expression_name)) {
		return Variant(frame.locals[expression_name]).stringify();
	}
	if (frame.members.has(expression_name)) {
		return Variant(frame.members[expression_name]).stringify();
	}
	if (!expression.begins_with("@")) {
		StringName ivar_name = "@" + expression;
		if (frame.members.has(ivar_name)) {
			return Variant(frame.members[ivar_name]).stringify();
		}
	}
	if (global_constants.has(expression_name)) {
		return Variant(global_constants[expression_name]).stringify();
	}
	int64_t core_constant_value = 0;
	if (_lunari_core_global_constant_value(expression_name, &core_constant_value)) {
		return Variant(core_constant_value).stringify();
	}
	List<Pair<String, Variant>> public_constants;
	get_public_constants(&public_constants);
	for (const Pair<String, Variant> &constant : public_constants) {
		if (constant.first == expression) {
			return constant.second.stringify();
		}
	}
	return String();
}

Vector<ScriptLanguage::StackInfo> LunariLanguage::debug_get_current_stack_info() {
	Vector<StackInfo> stack;
	for (const DebugFrame &frame : debug_stack) {
		StackInfo info;
		info.file = frame.source;
		info.func = frame.function;
		info.line = frame.line;
		stack.push_back(info);
	}
	return stack;
}
void LunariLanguage::reload_all_scripts() {
	Vector<LunariScript *> snapshot;
	for (LunariScript *script : scripts) {
		snapshot.push_back(script);
	}
	for (LunariScript *script : snapshot) {
		if (script) {
			script->reload();
			script->update_exports();
		}
	}
}

void LunariLanguage::reload_scripts(const Array &p_scripts, bool p_soft_reload) {
	for (int i = 0; i < p_scripts.size(); i++) {
		Ref<LunariScript> script = p_scripts[i];
		if (script.is_valid()) {
			script->reload();
			script->update_exports();
		}
	}
}

void LunariLanguage::reload_tool_script(const Ref<Script> &p_script, bool p_soft_reload) {
	Ref<LunariScript> script = p_script;
	if (script.is_valid()) {
		script->reload();
		script->update_exports();
	}
}
void LunariLanguage::get_recognized_extensions(List<String> *p_extensions) const { p_extensions->push_back("lu"); }

static void _lunari_add_public_function(List<MethodInfo> *p_functions, HashSet<StringName> *r_seen, const MethodInfo &p_info) {
	ERR_FAIL_NULL(p_functions);
	ERR_FAIL_NULL(r_seen);
	if (p_info.name == StringName() || r_seen->has(p_info.name)) {
		return;
	}
	r_seen->insert(p_info.name);
	p_functions->push_back(p_info);
}

static bool _lunari_prefers_helper_public_metadata(const StringName &p_function) {
	return p_function == SNAME("var_to_str") ||
			p_function == SNAME("str_to_var") ||
			p_function == SNAME("var_to_bytes") ||
			p_function == SNAME("bytes_to_var") ||
			p_function == SNAME("var_to_bytes_with_objects") ||
			p_function == SNAME("bytes_to_var_with_objects");
}

void LunariLanguage::get_public_functions(List<MethodInfo> *p_functions) const {
	ERR_FAIL_NULL(p_functions);
	HashSet<StringName> seen;
	List<StringName> variant_utilities;
	Variant::get_utility_function_list(&variant_utilities);
	for (const StringName &utility : variant_utilities) {
		if (_lunari_prefers_helper_public_metadata(utility) && LunariUtilityFunctions::function_exists(utility)) {
			continue;
		}
		_lunari_add_public_function(p_functions, &seen, Variant::get_utility_function_info(utility));
	}

	List<StringName> utilities;
	LunariUtilityFunctions::get_function_list(&utilities);
	for (const StringName &utility : utilities) {
		_lunari_add_public_function(p_functions, &seen, LunariUtilityFunctions::get_function_info(utility));
	}

	MethodInfo preload_info;
	preload_info.name = "preload";
	preload_info.arguments.push_back(PropertyInfo(Variant::STRING, "path"));
	preload_info.return_val = PropertyInfo(Variant::OBJECT, "", PROPERTY_HINT_RESOURCE_TYPE, "Resource");
	_lunari_add_public_function(p_functions, &seen, preload_info);

	MethodInfo assert_info;
	assert_info.name = "assert";
	assert_info.return_val.type = Variant::NIL;
	assert_info.arguments.push_back(PropertyInfo(Variant::BOOL, "condition"));
	assert_info.arguments.push_back(PropertyInfo(Variant::STRING, "message"));
	assert_info.default_arguments.push_back(String());
	_lunari_add_public_function(p_functions, &seen, assert_info);
}
void LunariLanguage::get_public_constants(List<Pair<String, Variant>> *p_constants) const {
	ERR_FAIL_NULL(p_constants);
	for (const KeyValue<StringName, Variant> &global : global_constants) {
		p_constants->push_back(Pair<String, Variant>(String(global.key), global.value));
	}
	for (int i = 0; i < CoreConstants::get_global_constant_count(); i++) {
		p_constants->push_back(Pair<String, Variant>(CoreConstants::get_global_constant_name(i), CoreConstants::get_global_constant_value(i)));
	}
	for (int i = 0; i < Variant::VARIANT_MAX; i++) {
		const String type_name = Variant::get_type_name(Variant::Type(i)).to_snake_case().to_upper();
		p_constants->push_back(Pair<String, Variant>("TYPE_" + type_name, i));
	}
	p_constants->push_back(Pair<String, Variant>("TYPE_MAX", Variant::VARIANT_MAX));
	p_constants->push_back(Pair<String, Variant>("PI", 3.14159265358979323846));
	p_constants->push_back(Pair<String, Variant>("TAU", 6.28318530717958647692));
	p_constants->push_back(Pair<String, Variant>("INF", Math::INF));
	p_constants->push_back(Pair<String, Variant>("NAN", Math::NaN));
	p_constants->push_back(Pair<String, Variant>("true", true));
	p_constants->push_back(Pair<String, Variant>("false", false));
	p_constants->push_back(Pair<String, Variant>("nil", Variant()));
}
