Error LunariLanguage::complete_code(const String &p_code, const String &p_path, Object *p_owner, List<CodeCompletionOption> *r_options, bool &r_force, String &r_call_hint) {
	ERR_FAIL_NULL_V(r_options, ERR_INVALID_PARAMETER);
	r_force = false;
	r_call_hint = String();

	const String current_line = _lunari_current_completion_line(p_code).strip_edges();
	if (current_line.begins_with("@export_range")) {
		r_call_hint = "@export_range(min: Float, max: Float, step: Float = 1.0)";
	} else if (current_line.begins_with("@export_enum")) {
		r_call_hint = "@export_enum(\"One\", \"Two\", \"Three\")";
	} else if (current_line.begins_with("@export_flags")) {
		r_call_hint = "@export_flags(\"A\", \"B\", \"C\")";
	} else if (current_line.begins_with("@export_file")) {
		r_call_hint = "@export_file(\"*.png,*.jpg,*.tscn\")";
	} else if (current_line.begins_with("@export_global_file")) {
		r_call_hint = "@export_global_file(\"*.png,*.jpg,*.tscn\")";
	} else if (current_line.begins_with("@export_save_file")) {
		r_call_hint = "@export_save_file(\"*.tres,*.res\")";
	} else if (current_line.begins_with("@export_global_save_file")) {
		r_call_hint = "@export_global_save_file(\"*.tres,*.res\")";
	} else if (current_line.begins_with("@export_exp_easing")) {
		r_call_hint = "@export_exp_easing(\"attenuation,positive_only\")";
	} else if (current_line.begins_with("@export_placeholder")) {
		r_call_hint = "@export_placeholder(\"Enter text\")";
	} else if (current_line.begins_with("@export_node_path")) {
		r_call_hint = "@export_node_path(\"Node2D,Control\")";
	} else if (current_line.begins_with("@export_resource_type")) {
		r_call_hint = "@export_resource_type(\"Texture2D,PackedScene\")";
	} else if (current_line.begins_with("@export_custom")) {
		r_call_hint = "@export_custom(hint: PropertyHint, hint_string: String, usage: PropertyUsageFlags)";
	} else if (current_line.begins_with("@export_tool_button")) {
		r_call_hint = "@export_tool_button(text: String, icon: String)";
	} else if (current_line.begins_with("@export_group")) {
		r_call_hint = "@export_group(\"Group\", \"prefix\")";
	} else if (current_line.begins_with("@warning_ignore_restore")) {
		r_call_hint = "@warning_ignore_restore(warning: String)";
	} else if (current_line.begins_with("@warning_ignore_start")) {
		r_call_hint = "@warning_ignore_start(warning: String)";
	} else if (current_line.begins_with("@warning_ignore")) {
		r_call_hint = "@warning_ignore(warning: String)";
	} else if (current_line.begins_with("@rpc")) {
		r_call_hint = "@rpc(\"any_peer\", \"call_local\", \"reliable\", channel: 0)";
	} else if (current_line.begins_with("signal ")) {
		r_call_hint = "signal name(arg: Type, ...)";
	} else if (current_line.begins_with("def ")) {
		r_call_hint = "def name(arg: Type = default): ReturnType";
	} else if (current_line.begins_with("class ")) {
		r_call_hint = "class Name < GodotBaseClass";
	}

	if (_lunari_complete_export_node_path_types(p_code, r_options)) {
		r_force = true;
		return OK;
	}
	if (_lunari_complete_annotation_string_options(p_code, r_options)) {
		r_force = true;
		return OK;
	}
	if (_lunari_complete_export_custom_constants(p_code, r_options)) {
		r_force = true;
		return OK;
	}
	if (_lunari_complete_export_tool_button_icons(p_code, r_options)) {
		r_force = true;
		return OK;
	}
	if (_lunari_is_expected_type_completion_context(p_code)) {
		_lunari_complete_expected_types(p_code, r_options);
		r_force = true;
		return OK;
	}

	const String early_receiver = _lunari_completion_receiver(p_code);
	if (!early_receiver.is_empty()) {
		LunariParser parser;
		LunariParser::Result result = parser.parse(p_code);
		LunariAST::Document ast = parser.parse_ast(p_code);
		Vector<LunariEditorSymbol> symbols;
		_lunari_collect_editor_symbols(ast.children, &symbols);
		StringName owner_class = p_owner ? p_owner->get_class_name() : StringName("Node");
		HashMap<StringName, StringName> type_map = _lunari_editor_type_map(result, ast, owner_class, p_code);

		HashMap<StringName, StringName>::ConstIterator ReceiverType = type_map.find(StringName(early_receiver));
		if (ReceiverType) {
			bool completed = _lunari_complete_godot_members(ReceiverType->value, r_options);
			completed = _lunari_complete_variant_builtin_members(ReceiverType->value, false, r_options) || completed;
			completed = _lunari_complete_user_members(ReceiverType->value, symbols, r_options) || completed;
			if (completed) {
				r_force = true;
				return OK;
			}
		}

		StringName receiver_type = StringName(early_receiver);
		if (!LunariGodotApi::has_class(receiver_type) && Engine::get_singleton() && Engine::get_singleton()->has_singleton(receiver_type)) {
			Object *singleton_object = Engine::get_singleton()->get_singleton_object(receiver_type);
			if (singleton_object) {
				receiver_type = singleton_object->get_class_name();
			}
		}
		if (LunariGodotApi::has_class(receiver_type) && _lunari_complete_godot_members(receiver_type, r_options)) {
			r_force = true;
			return OK;
		}
		if (_lunari_complete_variant_builtin_members(receiver_type, true, r_options)) {
			r_force = true;
			return OK;
		}
		Vector<LunariEditorSymbol> autoload_symbols;
		StringName autoload_class;
		if (_lunari_load_autoload_lunari_symbols(StringName(early_receiver), &autoload_symbols, &autoload_class, nullptr) &&
				_lunari_complete_user_members(autoload_class, autoload_symbols, r_options)) {
			r_force = true;
			return OK;
		}
	}

	static const char *keywords[] = { "require", "require_relative", "class", "module", "abstract", "def", "end", "public", "private", "protected", "static", "const", "case", "when", "match", "begin", "rescue", "ensure", "await", "return", "self", "super", "true", "false", "nil", "if", "elsif", "else", "unless", "while", "until", "for", "in", "break", "next", "redo", "yield", "as", "is", "include", "prepend", "extend", "implements", "attr_reader", "attr_writer", "attr_accessor", "alias", "alias_method", "undef", "undef_method", "remove_method" };
	for (const char *keyword : keywords) {
		_lunari_add_completion(r_options, keyword, CODE_COMPLETION_KIND_PLAIN_TEXT, LOCATION_OTHER, _lunari_help_text(keyword));
	}
	_lunari_complete_builtin_types(r_options);
	static const char *snippets[][2] = {
		{ "require \"godot\"", "Load the Godot API for Lunari." },
		{ "class Player < CharacterBody2D", "Ruby-style Godot inheritance." },
		{ "def ready", "Godot lifecycle callback called when the node enters the scene tree." },
		{ "def process(delta: Float)", "Godot frame callback." },
		{ "def physics_process(delta: Float)", "Godot fixed-timestep callback." },
		{ "@export @name: String = \"\"", "Typed Inspector export; Inspector shows name, not @name." },
		{ "@export_multiline @description: String = \"\"", "Multiline Inspector text export." },
		{ "@export_placeholder(\"Player name\") @display_name: String = \"\"", "String export with Inspector placeholder text." },
		{ "@export_resource_type(\"Texture2D\") @portrait: Resource", "Resource export constrained to a Godot resource type." },
		{ "@export_node_path(\"Label\") @label_path: NodePath", "NodePath export constrained to node types." },
		{ "@onready @label: Label = $Label", "Resolve a node path after the owner enters the scene tree." },
		{ "@rpc(\"any_peer\", \"call_local\", \"reliable\", channel: 0)", "Typed Godot multiplayer RPC annotation." },
		{ "$NodePath", "Godot node-path shorthand for get_node(\"NodePath\")." },
		{ "%SceneUniqueName", "Godot scene-unique node shorthand." },
		{ "signal greeted(message: String)", "Typed Godot signal declaration." },
		{ "Array<String>", "Typed Lunari array." },
		{ "Hash<String, Variant>", "Typed Lunari hash." },
		{ "String | Nil", "Nullable/union type." },
		{ "Callable<Variant>", "Callable type." },
		{ "Proc<String, Integer>", "Ruby-style block/proc surface type." },
	};
	for (uint32_t i = 0; i < sizeof(snippets) / sizeof(snippets[0]); i++) {
		_lunari_add_completion(r_options, snippets[i][0], CODE_COMPLETION_KIND_PLAIN_TEXT, LOCATION_OTHER, snippets[i][1]);
	}
	List<Pair<String, Variant>> constants;
	get_public_constants(&constants);
	for (const Pair<String, Variant> &constant : constants) {
		_lunari_add_completion(r_options, constant.first, CODE_COMPLETION_KIND_CONSTANT, LOCATION_OTHER, Variant(constant.second).stringify());
	}

	if (_lunari_complete_input_actions(p_code, r_options)) {
		r_force = true;
		return OK;
	}

	if (_lunari_complete_node_paths(p_code, p_owner, r_options)) {
		r_force = true;
		return OK;
	}

	if (_lunari_complete_file_paths(p_code, r_options)) {
		r_force = true;
		return OK;
	}

	_lunari_complete_active_scope_symbols(p_code, r_options);

	LunariParser parser;
	LunariParser::Result result = parser.parse(p_code);
	LunariAST::Document ast = parser.parse_ast(p_code);
	Vector<LunariEditorSymbol> symbols;
	_lunari_collect_editor_symbols(ast.children, &symbols);
	StringName owner_class = p_owner ? p_owner->get_class_name() : StringName("Node");
	HashMap<StringName, StringName> type_map = _lunari_editor_type_map(result, ast, owner_class, p_code);
	const String receiver = _lunari_completion_receiver(p_code);
	if (!receiver.is_empty()) {
		HashMap<StringName, StringName>::ConstIterator ReceiverType = type_map.find(StringName(receiver));
		if (ReceiverType) {
			bool completed = _lunari_complete_godot_members(ReceiverType->value, r_options);
			completed = _lunari_complete_variant_builtin_members(ReceiverType->value, false, r_options) || completed;
			completed = _lunari_complete_user_members(ReceiverType->value, symbols, r_options) || completed;
			if (completed) {
				r_force = true;
				return OK;
			}
		}
		StringName receiver_type = StringName(receiver);
		if (!LunariGodotApi::has_class(receiver_type) && Engine::get_singleton() && Engine::get_singleton()->has_singleton(receiver_type)) {
			Object *singleton_object = Engine::get_singleton()->get_singleton_object(receiver_type);
			if (singleton_object) {
				receiver_type = singleton_object->get_class_name();
			}
		}
		if (LunariGodotApi::has_class(receiver_type) && _lunari_complete_godot_members(receiver_type, r_options)) {
			r_force = true;
			return OK;
		}
		if (_lunari_complete_variant_builtin_members(receiver_type, true, r_options)) {
			r_force = true;
			return OK;
		}
		Vector<LunariEditorSymbol> autoload_symbols;
		StringName autoload_class;
		if (_lunari_load_autoload_lunari_symbols(StringName(receiver), &autoload_symbols, &autoload_class, nullptr) &&
				_lunari_complete_user_members(autoload_class, autoload_symbols, r_options)) {
			r_force = true;
			return OK;
		}
	}
	for (const LunariEditorSymbol &symbol : symbols) {
		if (symbol.name == StringName()) {
			continue;
		}
		CodeCompletionKind kind = CODE_COMPLETION_KIND_PLAIN_TEXT;
		switch (symbol.kind) {
			case LunariAST::Node::NODE_CLASS:
			case LunariAST::Node::NODE_MODULE:
				kind = CODE_COMPLETION_KIND_CLASS;
				break;
			case LunariAST::Node::NODE_ENUM:
				kind = CODE_COMPLETION_KIND_ENUM;
				break;
			case LunariAST::Node::NODE_CONST:
			case LunariAST::Node::NODE_ENUM_VALUE:
			case LunariAST::Node::NODE_TYPE_ALIAS:
				kind = CODE_COMPLETION_KIND_CONSTANT;
				break;
			case LunariAST::Node::NODE_METHOD:
				kind = CODE_COMPLETION_KIND_FUNCTION;
				break;
			case LunariAST::Node::NODE_SIGNAL:
				kind = CODE_COMPLETION_KIND_SIGNAL;
				break;
			case LunariAST::Node::NODE_FIELD:
				kind = CODE_COMPLETION_KIND_MEMBER;
				break;
			default:
				break;
		}
		_lunari_add_completion(r_options, symbol.name, kind, LOCATION_OTHER_USER_CODE, symbol.type == StringName() ? String() : String(symbol.type));
		if (symbol.kind == LunariAST::Node::NODE_FIELD) {
			StringName clean_name = _lunari_editor_symbol_lookup_name(symbol.name);
			if (clean_name != symbol.name) {
				_lunari_add_completion(r_options, clean_name, kind, LOCATION_OTHER_USER_CODE, symbol.type == StringName() ? String() : String(symbol.type));
			}
		}
	}
	for (const LunariParser::Class &klass : result.classes) {
		_lunari_add_completion(r_options, klass.name, CODE_COMPLETION_KIND_CLASS, LOCATION_OTHER_USER_CODE, klass.base == StringName() ? String() : String("< ") + String(klass.base));
	}
	for (const LunariParser::Field &field : result.fields) {
		_lunari_add_completion(r_options, field.name, CODE_COMPLETION_KIND_MEMBER, LOCATION_LOCAL, field.type);
	}
	for (const LunariParser::Method &method : result.methods) {
		_lunari_add_completion(r_options, method.name, CODE_COMPLETION_KIND_FUNCTION, LOCATION_LOCAL, method.return_type);
	}
	LocalVector<StringName> global_classes;
	ScriptServer::get_global_class_list(global_classes);
	for (const StringName &global_class : global_classes) {
		_lunari_add_completion(r_options, global_class, CODE_COMPLETION_KIND_CLASS, LOCATION_OTHER_USER_CODE, ScriptServer::get_global_class_native_base(global_class));
	}
	_lunari_complete_autoload_singletons(r_options);
	Vector<StringName> godot_classes;
	LunariGodotApi::get_class_names(&godot_classes);
	for (const StringName &godot_class : godot_classes) {
		_lunari_add_completion(r_options, godot_class, CODE_COMPLETION_KIND_CLASS, LOCATION_OTHER);
	}
	Vector<StringName> godot_properties;
	LunariGodotApi::get_property_names(owner_class, &godot_properties);
	for (const StringName &property : godot_properties) {
		_lunari_add_completion(r_options, property, CODE_COMPLETION_KIND_MEMBER, LOCATION_OTHER, LunariGodotApi::get_property_signature(owner_class, property));
	}
	Vector<StringName> godot_methods;
	LunariGodotApi::get_method_names(owner_class, &godot_methods);
	for (const StringName &method : godot_methods) {
		_lunari_add_completion(r_options, method, CODE_COMPLETION_KIND_FUNCTION, LOCATION_OTHER, LunariGodotApi::get_method_signature(owner_class, method));
	}
	Vector<StringName> godot_signals;
	LunariGodotApi::get_signal_names(owner_class, &godot_signals);
	for (const StringName &signal : godot_signals) {
		_lunari_add_completion(r_options, signal, CODE_COMPLETION_KIND_SIGNAL, LOCATION_OTHER, LunariGodotApi::get_signal_signature(owner_class, signal));
	}
	Vector<StringName> godot_constants;
	LunariGodotApi::get_constant_names(owner_class, &godot_constants);
	for (const StringName &constant : godot_constants) {
		int64_t value = 0;
		StringName enum_name;
		LunariGodotApi::get_constant(owner_class, constant, &value, &enum_name);
		String display = enum_name == StringName() ? itos(value) : String(enum_name) + " = " + itos(value);
		_lunari_add_completion(r_options, constant, CODE_COMPLETION_KIND_CONSTANT, LOCATION_OTHER, display);
	}
	Vector<StringName> godot_enums;
	LunariGodotApi::get_enum_names(owner_class, &godot_enums);
	for (const StringName &enum_name : godot_enums) {
		LunariGodotApi::EnumInfo enum_info;
		LunariGodotApi::get_enum_info(owner_class, enum_name, &enum_info);
		String display = enum_info.is_bitfield ? "bitfield" : "enum";
		if (!enum_info.constants.is_empty()) {
			display += " { ";
			for (int i = 0; i < enum_info.constants.size(); i++) {
				if (i > 0) {
					display += ", ";
				}
				display += String(enum_info.constants[i]);
			}
			display += " }";
		}
		_lunari_add_completion(r_options, enum_name, CODE_COMPLETION_KIND_ENUM, LOCATION_OTHER, display);
	}
	List<StringName> utilities;
	Variant::get_utility_function_list(&utilities);
	for (const StringName &utility : utilities) {
		if (_lunari_prefers_helper_public_metadata(utility) && LunariUtilityFunctions::function_exists(utility)) {
			continue;
		}
		MethodInfo info = Variant::get_utility_function_info(utility);
		const StringName return_type = Variant::has_utility_function_return_value(utility) ? StringName(Variant::get_type_name(Variant::get_utility_function_return_type(utility))) : StringName();
		_lunari_add_completion(r_options, utility, CODE_COMPLETION_KIND_FUNCTION, LOCATION_OTHER, _lunari_method_signature(info, return_type));
	}
	utilities.clear();
	LunariUtilityFunctions::get_function_list(&utilities);
	for (const StringName &utility : utilities) {
		if (Variant::has_utility_function(utility)) {
			continue;
		}
		MethodInfo info = LunariUtilityFunctions::get_function_info(utility);
		_lunari_add_completion(r_options, utility, CODE_COMPLETION_KIND_FUNCTION, LOCATION_OTHER, _lunari_method_signature(info, Variant::get_type_name(LunariUtilityFunctions::get_function_return_type(utility))));
	}
	List<MethodInfo> annotations;
	get_public_annotations(&annotations);
	for (const MethodInfo &annotation : annotations) {
		String detail = _lunari_method_signature(annotation);
		String help = _lunari_help_text(annotation.name);
		if (!help.is_empty()) {
			detail += detail.is_empty() ? help : " - " + help;
		}
		_lunari_add_completion(r_options, annotation.name, CODE_COMPLETION_KIND_PLAIN_TEXT, LOCATION_OTHER, detail);
	}
	return OK;
}

Error LunariLanguage::lookup_code(const String &p_code, const String &p_symbol, const String &p_path, Object *p_owner, LookupResult &r_result) {
	if (LunariGodotApi::has_class(p_symbol)) {
		r_result.type = LOOKUP_RESULT_CLASS;
		r_result.class_name = p_symbol;
		r_result.script_path = p_path;
		return OK;
	}
	if (ScriptServer::is_global_class(p_symbol)) {
		r_result.type = LOOKUP_RESULT_CLASS;
		r_result.class_name = p_symbol;
		r_result.script_path = ScriptServer::get_global_class_path(p_symbol);
		r_result.location = 0;
		return OK;
	}
	if (ProjectSettings::get_singleton() && ProjectSettings::get_singleton()->has_autoload(p_symbol)) {
		const ProjectSettings::AutoloadInfo autoload = ProjectSettings::get_singleton()->get_autoload(p_symbol);
		if (_lunari_is_lunari_autoload_singleton(autoload)) {
			r_result.type = LOOKUP_RESULT_CLASS;
			r_result.class_name = p_symbol;
			r_result.script_path = autoload.path;
			r_result.location = 0;
			return OK;
		}
	}
	LunariParser parser;
	LunariParser::Result result = parser.parse(p_code);
	LunariAST::Document ast = parser.parse_ast(p_code);
	StringName script_class = result.classes.is_empty() ? StringName() : result.classes[0].name;
	HashMap<StringName, StringName> type_map = _lunari_editor_type_map(result, ast, script_class, p_code);
	Vector<LunariEditorSymbol> symbols;
	_lunari_collect_editor_symbols(ast.children, &symbols);
	String receiver = _lunari_lookup_receiver_for_symbol(p_code, p_symbol);
	if (!receiver.is_empty()) {
		StringName receiver_key = receiver;
		StringName receiver_type;
		if (type_map.has(receiver_key)) {
			receiver_type = type_map[receiver_key];
			LookupResult receiver_result;
			if (_lunari_lookup_godot_member(receiver_type, p_symbol, receiver_result)) {
				r_result = receiver_result;
				r_result.script_path = p_path;
				return OK;
			}
		}
		if (LunariGodotApi::has_class(receiver_key)) {
			LookupResult receiver_result;
			if (_lunari_lookup_godot_member(receiver_key, p_symbol, receiver_result)) {
				r_result = receiver_result;
				r_result.script_path = p_path;
				return OK;
			}
		}
		Vector<LunariEditorSymbol> autoload_symbols;
		StringName autoload_class;
		String autoload_path;
		if (_lunari_load_autoload_lunari_symbols(receiver_key, &autoload_symbols, &autoload_class, &autoload_path)) {
			if (_lunari_lookup_user_member(autoload_class, autoload_symbols, p_symbol, autoload_path, r_result)) {
				return OK;
			}
		}
		if (receiver_type != StringName()) {
			if (_lunari_lookup_user_member(receiver_type, symbols, p_symbol, p_path, r_result)) {
				return OK;
			}
		}
	}
	for (const LunariEditorSymbol &symbol : symbols) {
		if (!_lunari_symbol_matches_lookup(symbol.name, p_symbol)) {
			continue;
		}
		r_result.script_path = p_path;
		r_result.location = symbol.line;
		r_result.doc_type = symbol.type;
		switch (symbol.kind) {
			case LunariAST::Node::NODE_CLASS:
			case LunariAST::Node::NODE_MODULE:
				r_result.type = LOOKUP_RESULT_CLASS;
				r_result.class_name = symbol.name;
				return OK;
			case LunariAST::Node::NODE_ENUM:
				r_result.type = LOOKUP_RESULT_CLASS_ENUM;
				r_result.class_name = symbol.owner;
				r_result.class_member = symbol.name;
				return OK;
			case LunariAST::Node::NODE_CONST:
			case LunariAST::Node::NODE_ENUM_VALUE:
			case LunariAST::Node::NODE_TYPE_ALIAS:
				r_result.type = symbol.owner == StringName() ? LOOKUP_RESULT_LOCAL_CONSTANT : LOOKUP_RESULT_CLASS_CONSTANT;
				r_result.class_name = symbol.owner;
				r_result.class_member = _lunari_editor_symbol_lookup_name(symbol.name);
				r_result.description = symbol.name;
				return OK;
			case LunariAST::Node::NODE_METHOD:
				r_result.type = LOOKUP_RESULT_CLASS_METHOD;
				r_result.class_name = symbol.owner;
				r_result.class_member = symbol.name;
				return OK;
			case LunariAST::Node::NODE_SIGNAL:
				r_result.type = LOOKUP_RESULT_CLASS_SIGNAL;
				r_result.class_name = symbol.owner;
				r_result.class_member = symbol.name;
				return OK;
			case LunariAST::Node::NODE_FIELD:
				r_result.type = LOOKUP_RESULT_CLASS_PROPERTY;
				r_result.class_name = symbol.owner;
				r_result.class_member = _lunari_editor_symbol_lookup_name(symbol.name);
				r_result.description = _lunari_editor_symbol_lookup_name(symbol.name);
				return OK;
			default:
				break;
		}
	}
	for (const LunariParser::Class &klass : result.classes) {
		if (klass.name == p_symbol) {
			r_result.type = LOOKUP_RESULT_CLASS;
			r_result.class_name = klass.name;
			r_result.script_path = p_path;
			r_result.location = klass.line;
			return OK;
		}
	}
	for (const LunariParser::Field &field : result.fields) {
		if (_lunari_symbol_matches_lookup(field.name, p_symbol)) {
			r_result.type = LOOKUP_RESULT_LOCAL_VARIABLE;
			r_result.description = _lunari_editor_symbol_lookup_name(field.name);
			r_result.doc_type = field.type;
			r_result.script_path = p_path;
			r_result.location = field.line;
			return OK;
		}
	}
	for (const LunariParser::Method &method : result.methods) {
		if (method.name == p_symbol) {
			r_result.type = LOOKUP_RESULT_CLASS_METHOD;
			r_result.class_member = method.name;
			r_result.class_name = method.owner_class;
			r_result.script_path = p_path;
			r_result.location = method.line;
			return OK;
		}
	}
	String direct_help = _lunari_help_text(p_symbol);
	if (!direct_help.is_empty()) {
		r_result.type = LOOKUP_RESULT_LOCAL_VARIABLE;
		r_result.description = direct_help;
		r_result.script_path = p_path;
		return OK;
	}
	List<Pair<String, Variant>> constants;
	get_public_constants(&constants);
	for (const Pair<String, Variant> &constant : constants) {
		if (constant.first == p_symbol) {
			r_result.type = LOOKUP_RESULT_LOCAL_CONSTANT;
			r_result.description = constant.first;
			r_result.value = Variant(constant.second).stringify();
			r_result.doc_type = Variant::get_type_name(Variant(constant.second).get_type());
			return OK;
		}
	}
	if (p_symbol.begins_with("@")) {
		List<MethodInfo> annotations;
		get_public_annotations(&annotations);
		for (const MethodInfo &annotation : annotations) {
			if (annotation.name == p_symbol) {
				r_result.type = LOOKUP_RESULT_CLASS_ANNOTATION;
				r_result.class_member = p_symbol;
				r_result.description = _lunari_method_signature(annotation);
				return OK;
			}
		}
	}
	StringName owner_class = p_owner ? p_owner->get_class_name() : StringName("Node");
	if (_lunari_lookup_godot_member(owner_class, p_symbol, r_result)) {
		r_result.script_path = p_path;
		return OK;
	}
	return ERR_DOES_NOT_EXIST;
}

void LunariLanguage::profiling_start() {
	profiling = true;
	profile_call_counts.clear();
	profile_frame_call_counts.clear();
	profile_last_frame_call_counts.clear();
}

void LunariLanguage::profiling_stop() {
	profiling = false;
	profile_frame_call_counts.clear();
	profile_last_frame_call_counts.clear();
}

void LunariLanguage::profiling_set_save_native_calls(bool p_enable) {
	profiling_save_native_calls = p_enable;
}

static int _lunari_write_profile_data(const HashMap<StringName, uint64_t> &p_counts, ScriptLanguage::ProfilingInfo *p_info_arr, int p_info_max) {
	if (!p_info_arr || p_info_max <= 0) {
		return 0;
	}
	int written = 0;
	for (const KeyValue<StringName, uint64_t> &entry : p_counts) {
		if (written >= p_info_max) {
			break;
		}
		p_info_arr[written].signature = entry.key;
		p_info_arr[written].call_count = entry.value;
		p_info_arr[written].self_time = 0;
		p_info_arr[written].total_time = 0;
		p_info_arr[written].internal_time = 0;
		written++;
	}
	return written;
}

int LunariLanguage::profiling_get_accumulated_data(ProfilingInfo *p_info_arr, int p_info_max) {
	return _lunari_write_profile_data(profile_call_counts, p_info_arr, p_info_max);
}

int LunariLanguage::profiling_get_frame_data(ProfilingInfo *p_info_arr, int p_info_max) {
	return _lunari_write_profile_data(profile_last_frame_call_counts, p_info_arr, p_info_max);
}

void LunariLanguage::frame() {
	if (!profiling) {
		return;
	}
	profile_last_frame_call_counts = profile_frame_call_counts;
	profile_frame_call_counts.clear();
}

LunariLanguage::LunariLanguage() {
	singleton = this;
}

LunariLanguage::~LunariLanguage() {
	if (singleton == this) {
		singleton = nullptr;
	}
}

Ref<Resource> ResourceFormatLoaderLunariScript::load(const String &p_path, const String &p_original_path, Error *r_error, bool p_use_sub_threads, float *r_progress, CacheMode p_cache_mode) {
	if (p_path.is_empty() || ResourceLoader::get_resource_type(p_path.get_slice("::", 0)) == "PackedScene") {
		if (r_error) {
			*r_error = OK;
		}
		Ref<LunariScript> script;
		script.instantiate();
		script->set_path_cache(p_original_path);
		return script;
	}

	Error err = OK;
	String source = FileAccess::get_file_as_string(p_path, &err);
	if (r_error) {
		*r_error = err;
	}
	ERR_FAIL_COND_V_MSG(err != OK, Ref<Resource>(), "Cannot load Lunari script file '" + p_path + "'.");

	Ref<LunariScript> script;
	Ref<Resource> existing = ResourceCache::get_ref(p_original_path);
	bool ignoring = p_cache_mode == CACHE_MODE_IGNORE || p_cache_mode == CACHE_MODE_IGNORE_DEEP;
	bool replacing = p_cache_mode == CACHE_MODE_REPLACE || p_cache_mode == CACHE_MODE_REPLACE_DEEP;
	if (!ignoring && existing.is_valid()) {
		script = existing;
	} else {
		script.instantiate();
	}

	script->set_source_code(source);
	if (ignoring) {
		script->set_path_cache(p_original_path);
	} else if (existing.is_null() && !replacing) {
		script->set_path(p_original_path);
	} else if (replacing) {
		script->set_path(p_original_path, true);
	}
	script->reload();
	return script;
}

void ResourceFormatLoaderLunariScript::get_recognized_extensions(List<String> *p_extensions) const {
	p_extensions->push_back("lu");
}

bool ResourceFormatLoaderLunariScript::handles_type(const String &p_type) const {
	return p_type == "Script" || p_type == "LunariScript";
}

String ResourceFormatLoaderLunariScript::get_resource_type(const String &p_path) const {
	return p_path.get_extension().to_lower() == "lu" ? "LunariScript" : String();
}

void ResourceFormatLoaderLunariScript::get_dependencies(const String &p_path, List<String> *p_dependencies, bool p_add_types) {
	ERR_FAIL_NULL(p_dependencies);

	Error err = OK;
	String source = FileAccess::get_file_as_string(p_path, &err);
	ERR_FAIL_COND_MSG(err != OK, "Cannot open Lunari script file '" + p_path + "'.");

	HashSet<String> seen;
	_lunari_collect_required_script_paths(source, p_path, seen, p_dependencies, p_add_types);
}

static void _lunari_collect_type_classes_from_type(const StringName &p_type, HashSet<StringName> *r_classes) {
	ERR_FAIL_NULL(r_classes);
	String type = String(p_type).strip_edges();
	if (type.is_empty()) {
		return;
	}
	Vector<String> queue;
	queue.push_back(type);
	while (!queue.is_empty()) {
		String current = queue[queue.size() - 1].strip_edges();
		queue.remove_at(queue.size() - 1);
		if (current.is_empty()) {
			continue;
		}
		if (current.ends_with("?")) {
			current = current.substr(0, current.length() - 1).strip_edges();
		}
		int pipe = current.find("|");
		if (pipe >= 0) {
			for (const String &part : current.split("|")) {
				queue.push_back(part.strip_edges());
			}
			continue;
		}
		int generic = current.find("<");
		if (generic > 0 && current.ends_with(">")) {
			String base = current.substr(0, generic).strip_edges();
			if (!base.is_empty()) {
				queue.push_back(base);
			}
			String args = current.substr(generic + 1, current.length() - generic - 2);
			for (const String &arg : args.split(",")) {
				queue.push_back(arg.strip_edges());
			}
			continue;
		}
		if (ClassDB::class_exists(current)) {
			r_classes->insert(StringName(current));
		}
	}
}

static void _lunari_collect_classes_from_ast(const Vector<LunariAST::Node> &p_nodes, HashSet<StringName> *r_classes) {
	ERR_FAIL_NULL(r_classes);
	for (const LunariAST::Node &node : p_nodes) {
		if (node.kind == LunariAST::Node::NODE_CLASS) {
			_lunari_collect_type_classes_from_type(node.base, r_classes);
		}
		if (node.type != StringName()) {
			_lunari_collect_type_classes_from_type(node.type, r_classes);
		}
		for (const LunariAST::Parameter &parameter : node.parameters) {
			_lunari_collect_type_classes_from_type(parameter.type, r_classes);
		}
		_lunari_collect_classes_from_ast(node.children, r_classes);
		_lunari_collect_classes_from_ast(node.else_children, r_classes);
		_lunari_collect_classes_from_ast(node.rescue_children, r_classes);
	}
}

static bool _lunari_is_identifier_start(char32_t p_char) {
	return (p_char >= 'A' && p_char <= 'Z') || (p_char >= 'a' && p_char <= 'z') || p_char == '_';
}

static bool _lunari_is_identifier_char(char32_t p_char) {
	return _lunari_is_identifier_start(p_char) || (p_char >= '0' && p_char <= '9');
}

static void _lunari_collect_native_classes_from_identifiers(const String &p_source, HashSet<StringName> *r_classes) {
	ERR_FAIL_NULL(r_classes);

	bool in_string = false;
	char32_t quote = 0;
	bool in_line_comment = false;
	bool in_block_comment = false;

	for (int i = 0; i < p_source.length();) {
		const char32_t c = p_source[i];
		const char32_t next = i + 1 < p_source.length() ? p_source[i + 1] : 0;

		if (in_line_comment) {
			if (c == '\n' || c == '\r') {
				in_line_comment = false;
			}
			i++;
			continue;
		}

		if (in_block_comment) {
			if (c == '=' && next == 'e') {
				const String tail = p_source.substr(i, 4);
				if (tail == "=end") {
					i += 4;
					in_block_comment = false;
					continue;
				}
			}
			i++;
			continue;
		}

		if (in_string) {
			if (c == '\\') {
				i += 2;
				continue;
			}
			if (c == quote) {
				in_string = false;
				quote = 0;
			}
			i++;
			continue;
		}

		if (c == '#') {
			in_line_comment = true;
			i++;
			continue;
		}
		if (c == '=' && next == 'b' && p_source.substr(i, 6) == "=begin") {
			in_block_comment = true;
			i += 6;
			continue;
		}
		if (c == '"' || c == '\'') {
			in_string = true;
			quote = c;
			i++;
			continue;
		}
		if (c == '%' && next == 'w') {
			const int open = i + 2;
			if (open < p_source.length()) {
				const char32_t open_char = p_source[open];
				char32_t close_char = 0;
				if (open_char == '[') {
					close_char = ']';
				} else if (open_char == '(') {
					close_char = ')';
				} else if (open_char == '{') {
					close_char = '}';
				}
				if (close_char != 0) {
					i = open + 1;
					while (i < p_source.length() && p_source[i] != close_char) {
						if (p_source[i] == '\\') {
							i++;
						}
						i++;
					}
					if (i < p_source.length()) {
						i++;
					}
					continue;
				}
			}
		}

		if (_lunari_is_identifier_start(c)) {
			const int start = i;
			i++;
			while (i < p_source.length() && _lunari_is_identifier_char(p_source[i])) {
				i++;
			}
			const String identifier = p_source.substr(start, i - start);
			if (ClassDB::class_exists(identifier)) {
				r_classes->insert(StringName(identifier));
			}
			continue;
		}

		i++;
	}
}

void ResourceFormatLoaderLunariScript::get_classes_used(const String &p_path, HashSet<StringName> *r_classes) {
	ERR_FAIL_NULL(r_classes);

	Error err = OK;
	String source = FileAccess::get_file_as_string(p_path, &err);
	ERR_FAIL_COND_MSG(err != OK, "Cannot open Lunari script file '" + p_path + "'.");

	_lunari_collect_native_classes_from_identifiers(source, r_classes);

	LunariParser parser;
	LunariAST::Document document = parser.parse_ast(source);
	_lunari_collect_classes_from_ast(document.children, r_classes);

	LunariAnalyzer analyzer;
	const LunariAnalyzer::Result &analysis = analyzer.analyze(source, p_path);
	_lunari_collect_type_classes_from_type(analysis.native_base, r_classes);
	for (const LunariAnalyzer::Field &field : analysis.fields) {
		_lunari_collect_type_classes_from_type(field.type, r_classes);
	}
	for (const LunariAnalyzer::Method &method : analysis.methods) {
		_lunari_collect_type_classes_from_type(method.return_type, r_classes);
		for (const LunariAnalyzer::Parameter &parameter : method.parameters) {
			_lunari_collect_type_classes_from_type(parameter.type, r_classes);
		}
	}
}

Error ResourceFormatLoaderLunariScript::rename_dependencies(const String &p_path, const HashMap<String, String> &p_map) {
	Error err = OK;
	String source = FileAccess::get_file_as_string(p_path, &err);
	ERR_FAIL_COND_V_MSG(err != OK, err, "Cannot open Lunari script file '" + p_path + "'.");

	bool changed = false;
	String rewritten = _lunari_rewrite_required_script_paths(source, p_path, p_map, &changed);
	if (!changed) {
		return OK;
	}

	Ref<FileAccess> file = FileAccess::open(p_path, FileAccess::WRITE, &err);
	ERR_FAIL_COND_V_MSG(err != OK, err, "Cannot rewrite Lunari script dependencies in '" + p_path + "'.");
	file->store_string(rewritten);
	if (file->get_error() != OK && file->get_error() != ERR_FILE_EOF) {
		return ERR_CANT_CREATE;
	}
	return OK;
}

Error ResourceFormatSaverLunariScript::save(const Ref<Resource> &p_resource, const String &p_path, uint32_t p_flags) {
	Ref<LunariScript> script = p_resource;
	ERR_FAIL_COND_V(script.is_null(), ERR_INVALID_PARAMETER);

	Error err = OK;
	Ref<FileAccess> file = FileAccess::open(p_path, FileAccess::WRITE, &err);
	ERR_FAIL_COND_V_MSG(err != OK, err, "Cannot save Lunari script file '" + p_path + "'.");

	file->store_string(script->get_source_code());
	if (file->get_error() != OK && file->get_error() != ERR_FILE_EOF) {
		return ERR_CANT_CREATE;
	}
	return OK;
}

void ResourceFormatSaverLunariScript::get_recognized_extensions(const Ref<Resource> &p_resource, List<String> *p_extensions) const {
	if (Object::cast_to<LunariScript>(*p_resource)) {
		p_extensions->push_back("lu");
	}
}

bool ResourceFormatSaverLunariScript::recognize(const Ref<Resource> &p_resource) const {
	return Object::cast_to<LunariScript>(*p_resource) != nullptr;
}
